#include <bits/stdc++.h>

using namespace std;

#define MOD 1000000007

// funcție care numără drumurile elementare de la sursa la destinație
void numarare_drumuri(int sursa, int destinatie,
  const vector < vector < int >> & intersectie, vector < long long > & dp) {
  // initializez numărul de drumuri la nodul sursă cu 1
  dp[sursa] = 1;
  // parcurg toate nodurile de la sursă la destinație
  for (int i = sursa; i <= destinatie; i++) {
    // continui doar dacă există drumuri către nodul curent
    if (dp[i] != 0) {
      // parcurg toți succesori nodului curent
      // adaug numărul de drumuri de la nodul curent la succesorii săi
      for (size_t j = 0; j < intersectie[i].size(); j++) {
        int succesor = intersectie[i][j];
        dp[succesor] = (dp[succesor] + dp[i]) % MOD;
      }
    }
  }
}

int main() {
  int numar_noduri, numar_muchii;
  ifstream fin("numarare.in");
  ofstream fout("numarare.out");
  // citesc numărului de noduri și muchii
  fin >> numar_noduri >> numar_muchii;
  // initializez grafurilor graf1 și graf2
  vector < vector < int >> graf1(numar_noduri + 1), graf2(numar_noduri + 1);

  // citesc celor două grafuri
  int nod1, nod2;
  for (int i = 0; i < numar_muchii; i++) {
    fin >> nod1 >> nod2;
    graf1[nod1].push_back(nod2);
  }
  for (int i = 0; i < numar_muchii; i++) {
    fin >> nod1 >> nod2;
    graf2[nod1].push_back(nod2);
  }

  // intersecția reprezintă nodurile comune ale celor două grafuri
  // ea este reprezentată sub forma unui vector de vectori
  vector < vector < int >> intersectie(numar_noduri + 1);
  // auxiliar este un vector de vectori, fiind o structura auxiliara
  // care ajuta la gasirea intersectiei
  vector < vector < int >> auxiliar(numar_noduri + 1);
  // construirea intersecției graf1 și graf2
  // parcurg fiecare nod de la 1 la numar_noduri
  for (int i = 1; i <= numar_noduri; i++) {
    // parcurg lista de succesori ai nodului i din graf2
    for (size_t j = 0; j < graf2[i].size(); j++) {
      // gasesc succesorul nodului i în graf2
      int nod2 = graf2[i][j];
      // adaug succesorul în auxiliar pentru nodul i
      auxiliar[i].push_back(nod2);
    }
  }

  // parcurg fiecare nod de la 1 la numar_noduri
  for (int i = 1; i <= numar_noduri; i++) {
    // parcurg lista de succesori ai nodului i din graf1
    for (size_t j = 0; j < graf1[i].size(); j++) {
      // gasesc succesorul nodului i în graf1
      int nod2 = graf1[i][j];
      // verific dacă nodul2 este și succesor al nodului i în graf2
      if (find(auxiliar[i].begin(), auxiliar[i].end(), nod2)
      != auxiliar[i].end()) {
        // daca nodul2 este succesor comun în ambele grafuri,
        // adaugă în graful de intersecție
        intersectie[i].push_back(nod2);
      }
    }
  }

  // folosim programarea dinamica pentru a numara drumurile
  vector < long long > dp(numar_noduri + 1, 0);
  numarare_drumuri(1, numar_noduri, intersectie, dp);
  // afisez numărul de drumuri de la nodul 1 la nodul n
  fout << dp[numar_noduri] << '\n';

  fin.close();
  fout.close();
  return 0;
}

import java.io.BufferedReader;
import java.io.BufferedWriter;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.ArrayList;
import java.util.Collections;
import java.util.LinkedList;
import java.util.List;
import java.util.Queue;
import java.util.StringTokenizer;


public class Numarare {
	private int N, M;
	private List<Integer>[] adj1, adj2, comun;
	private int[] grad;
	private long[] dp;
	private final int mod = 1000000007;
	private final int Nmax = 100000;

	public static void main(String[] args) throws IOException {
		Numarare numarare = new Numarare();
		numarare.readInput();
		numarare.writeOutput(numarare.getResult());
	}

	private void alloc(int N) {
		adj1 = new ArrayList[N + 1];
		adj2 = new ArrayList[N + 1];
		comun = new ArrayList[N + 1];
		grad = new int[Nmax + 1];
		dp = new long[Nmax + 1];
		for (int i = 0; i <= N; i++) {
			adj1[i] = new ArrayList<>();
			adj2[i] = new ArrayList<>();
			comun[i] = new ArrayList<>();
		}
	}

	private void readInput() throws IOException {
		BufferedReader in = new BufferedReader(new FileReader("numarare.in"));
		StringTokenizer st = new StringTokenizer(in.readLine());
		N = Integer.parseInt(st.nextToken());
		M = Integer.parseInt(st.nextToken());
		alloc(N);

		for (int i = 0; i < M; i++) {
			st = new StringTokenizer(in.readLine());
			int a = Integer.parseInt(st.nextToken());
			int b = Integer.parseInt(st.nextToken());
			adj1[a].add(b);
		}
		for (int i = 0; i < M; i++) {
			st = new StringTokenizer(in.readLine());
			int a = Integer.parseInt(st.nextToken());
			int b = Integer.parseInt(st.nextToken());
			adj2[a].add(b);
		}
		in.close();
	}

	private void writeOutput(long result) throws IOException {
		PrintWriter out = new PrintWriter(new BufferedWriter(new FileWriter("numarare.out")));
		out.println(result);
		out.close();
	}

	private void findCommon() {
		dp[1] = 1;
		Queue<Integer> queue = new LinkedList<>();
		queue.add(1);

		while (!queue.isEmpty()) {
			int nod = queue.poll();
			for (int i = 0; i < comun[nod].size(); i++) {
				int next = comun[nod].get(i);
				dp[next] = (dp[next] + dp[nod]) % mod;
				grad[next]--;
				if (grad[next] == 0) {
					queue.add(next);
				}
			}
		}
	}

	private long getResult() {
		for (int i = 1; i <= N; i++) {
			Collections.sort(adj1[i]);
			Collections.sort(adj2[i]);

			comun[i] = intersection(adj1[i], adj2[i]);

			for (int j : comun[i]) {
				grad[j]++;
			}
		}

		findCommon();

		return dp[N];
	}

	private List<Integer> intersection(List<Integer> list1, List<Integer> list2) {
		int i = 0, j = 0;
		int n = list1.size(), m = list2.size();
		List<Integer> result = new ArrayList<>();
		while (i < n && j < m) {
			if (list1.get(i).equals(list2.get(j))) {
				result.add(list1.get(i));
				i++;
				j++;
			} else if (list1.get(i) < list2.get(j)) {
				i++;
			} else {
				j++;
			}
		}
		return result;
	}
}
